#include <stdio.h>

int main() {
    int T, choice;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &choice) != 1) break;
        switch (choice) {
            case 1:
                printf("Option 1 selected\n");
                break;
            case 2:
                printf("Option 2 selected\n");
                break;
            case 3:
                printf("Option 3 selected\n");
                break;
            default:
                printf("Invalid choice\n");
        }
    }
    return 0;
}

