#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        if idx >= len(data):
            break
        choice = int(data[idx]); idx += 1
        if choice == 1:
            out.append("Option 1 selected")
        elif choice == 2:
            out.append("Option 2 selected")
        elif choice == 3:
            out.append("Option 3 selected")
        else:
            out.append("Invalid choice")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

